import type { Conjugations } from '../types/verb'

const persons = ['ich', 'du', 'er', 'wir', 'ihr', 'sie'] as const

export default function ConjugationTable({
  conjugations,
}: {
  conjugations?: Conjugations
}) {
  const indikativ = conjugations?.indikativ

  if (!indikativ) {
    return <p>暂无变位信息</p>
  }

  return (
    <table border={1} cellPadding={6} style={{ marginTop: 8 }}>
      <thead>
        <tr>
          <th></th>
          <th>现在时</th>
          <th>过去时</th>
          <th>完成时</th>
        </tr>
      </thead>
      <tbody>
        {persons.map(p => (
          <tr key={p}>
            <td>{p}</td>
            <td>{indikativ.prasens?.[p] || '—'}</td>
            <td>{indikativ.prateritum?.[p] || '—'}</td>
            <td>{indikativ.perfekt?.[p] || '—'}</td>
          </tr>
        ))}
      </tbody>
    </table>
  )
}

import { useState } from 'react'
import type { Verb } from '../types/verb'
import ConjugationTable from './ConjugationTable'

export default function VerbItem({ verb }: { verb: Verb }) {
  const [open, setOpen] = useState(false)

  return (
    <li style={{ marginBottom: 12 }}>
      <strong>{verb.word}</strong> — {verb.meaning}
      <br />
      <button onClick={() => setOpen(o => !o)}>
        {open ? '隐藏变位' : '查看变位'}
      </button>

      {open && <ConjugationTable conjugations={verb.conjugations} />}
    </li>
  )
}

export type Person = 'ich' | 'du' | 'er' | 'wir' | 'ihr' | 'sie'

export interface Tense {
  ich?: string
  du?: string
  er?: string
  wir?: string
  ihr?: string
  sie?: string
}

export interface Indikativ {
  prasens?: Tense
  prateritum?: Tense
  perfekt?: Tense
}

export interface Conjugations {
  indikativ?: Indikativ
}

export interface Verb {
  id: number
  word: string
  meaning: string
  conjugations?: Conjugations
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// https://vite.dev/config/
export default defineConfig({
  plugins: [react()],
})

import axios from 'axios'
import type { Verb } from '../types/verb'

const BASE_URL = 'http://localhost:8002'

export async function fetchVerbs(): Promise<Verb[]> {
  const res = await axios.get(`${BASE_URL}/verbs`)
  return res.data
}

export async function createVerb(payload: Partial<Verb>): Promise<Verb> {
  const res = await axios.post(`${BASE_URL}/verbs`, payload)
  return res.data
}

export type Person = 'ich' | 'du' | 'er' | 'wir' | 'ihr' | 'sie'

export interface Tense {
  ich?: string
  du?: string
  er?: string
  wir?: string
  ihr?: string
  sie?: string
}

export interface Indikativ {
  prasens?: Tense
  prateritum?: Tense
  perfekt?: Tense
}

export interface Conjugations {
